    ["people"] = "The people sector consumes one <sprite=0> for every <sprite=1> it generates. \\nIf there is no <sprite=0>, it will spawn the <color=white>People Starving event</color> instead.",
    ["sector_area"] = "Sector Area",
    ["sector_area_description"] = "Each sector has its respective <color=white>area</color> where you can put cards. \\n\\n\\nYou can <color=white>expand it</color> by selecting the sector card and buying the <color=white>Increase sector size</color> upgrade.\\n",
    ["sectors"] = "Sectors",
    ["sectors_info"] = "Sectors generate different types of resources: <sprite=0> <sprite=1> <sprite=2>",
    ["tips"] = "Tips & Strategies",
    ["tips_info"] = "• You can buy the same upgrade more than once. However, the price <color=white>increases</color> each time.\\n\\n\\n• Some cards give you <color=white>bonus resources</color> when they are created.\\n\\n\\n• It’s important to try to <color=white>limit your emissions</color> as soon as possible.\\n\\n\\n• Don't forget to eventually <color=white>destroy cards</color> that produce too many emissions!\\n\\n\\n• Investing in cards which don't seem very effective can lead to some useful cards later on.\\n\\n\\n•  <color=white>Speeding up</color> a sector also means it will <color=white>create emissions faster</color>.\\n\\n\\n• When you see a <color=white>bouncing cog</color> on a card, it means you can afford to upgrade it.\\n\\n\\n• The faster the <#C8B445>People</color> Sector runs, the <color=white>faster</color> it consumes <sprite=0>.\\n\\n\\n• The <#EB44A0>Industry</color> sector can generate <sprite=0> very fast but it produces a <color=white>lot of emissions</color>.\\n\\n\\n• Cards from <#41A40B>Ecosystems</color> may generate <sprite=0> slower but they produce far <color=white>less emissions</color>. They also help <color=white>prevent some crises</color>.\\n\\n\\n• Cards from <#6282E6>Science</color> help you <color=white>remove emissions</color> and <color=white>prevent some crises</color>.\\n\\n\\n",
