  ["tipping_point_reached"] = "Tipping Point",
  ["tipping_points"] = {
    ["tipping_point_0"] = "The world has warmed by 0,5-1 degrees Celsius, compared to the pre-industrial levels. You can expect natural disasters of a historically unprecedented extent.",
    ["tipping_point_1"] = "The world has warmed by 1.5 degrees Celsius, more than 70 % of coral reefs are dead. Acidified sea water means harsh decline in biodiversity of marine life. The Western Antarctic glacier and permafrost begin to melt and release methane emissions.",
    ["tipping_point_2"] = "The world has warmed by 2 degrees Celsius. Coral reefs in tropical areas have completely perished, taking the dependent marine life with them. For the first time ever, northern pole often gets iceless during summer. Pollinators are dying. Times of drought, fires, hunger and water scarcity are ahead.",
    ["tipping_point_3"] = "The world has warmed by 2.5 degrees Celsius. Gulf Stream is disrupted. Amazonian forest is gradually drying out... Part of the planet descended into a chaos of wars for the control of resources. Huge masses of people are forced to migrate into more habitable areas.",
    ["tipping_point_4"] = "The world has warmed by 3 degrees Celsius. Large swaths of land are turning into deserts and new areas too hot and damp for humans to survive are forming. Humanity is forced to move up north, causing unprecedented migration and death as there's not enough resources.",
    ["tipping_point_5"] = "The world has warmed by 3.5 degrees Celsius and 30% of Earth's surface is uninhabitable. Rainforests became deserts, megadroughts abound. Areas with formerly temperate climate are the only places where agriculture is still possible. ",
    ["tipping_point_6"] = "The world has warmed by 4 degrees Celsius. Oceans cease to mix and are losing oxygen. Marine life is nearly dead and massive migration towards the poles begins. Civilisation collapses, with only a fraction of humanity still alive and ruled by the \\",
    ["tipping_point_7"] = "The world has warmed by 5 degrees Celsius. The only habitable areas of Earth are the Poles, the rest turned into parched deserts and extremely hot and damp regions - most life, even on land, is extinct. Only a few thousand people still survive in tribal societies.",
  },
  ["tipping_points_enc"] = {
    ["tipping_point_0"] = "The world has warmed by 0,5-1 degrees Celsius, compared to the pre-industrial levels. You can expect natural disasters of a historically unprecedented extent.",
    ["tipping_point_0_name"] = "Warming of 0.5-1 °C",
    ["tipping_point_1"] = "The world has warmed by 1.5 degrees Celsius. Oceans are much more polluted, so more than 70 % of coral reefs are dead. Acidified sea water means harsh decline in biodiversity of marine life. The Western Antarctic glacier starts to melt, along with the northern permafrost, which begins to release methane emissions.",
    ["tipping_point_1_name"] = "Warming of 1.5 °C",
    ["tipping_point_2"] = "The world has warmed by 2 degrees Celsius, and the situation is critical. Coral reefs in tropical areas have completely perished, taking the dependent marine life with them. For the first time ever, northern pole often gets iceless during summer. Arctic biodiversity is in alarming decline. Greenland and Arctic melts, raising the sea levels. Western Antarctic glacier collapsed, pollinators are dying out. Times of drought and fires are ahead, hunger is ever present, water is scarce, and people get increasingly displaced.",
    ["tipping_point_2_name"] = "Warming of 2 °C",
    ["tipping_point_3"] = "The world has warmed by 2.5 degrees Celsius. As Greenland and Arctic melts more and more, Gulf Stream is disrupted, invoking cascading climate changes. Amazonian forest is gradually drying out and is turning into a savannah as a result of deforestation, releasing additional emissions into the Earth's atmosphere. Large areas of northern boreal forest are in flames, producing additional pollutants. A part of the planet descended into a chaos of wars for the control of resources. Huge masses of people are forced to migrate into more habitable areas.",
    ["tipping_point_3_name"] = "Warming of 2.5 °C",
    ["tipping_point_4"] = "The world has warmed by 3 degrees Celsius. Rainforests are still withering, the planet is burning and is suffering climate catastrophes. Large swaths of land are turning into deserts and new areas too hot and damp for humans to survive. There is less and less permafrost. Humanity is forced to move up north, causing unprecedented migration and death as there's not enough resources to feed everyone. International collaboration and community is a thing of the past.",
    ["tipping_point_4_name"] = "Warming of 3 °C",
    ["tipping_point_5"] = "The world has warmed by 3.5 degrees Celsius and 30% of Earth's surface is uninhabitable. Rainforests are gone, turned into deserts. Mountain glaciers are no more and megadroughts abound. Precipitations appear on the edge of Sahara and vegetation starts to green, but the temperature and humidity are too high for humans to stay alive. The eastern arctic glacier begins to melt. The remaining humans inhabit the Northern hemisphere as the areas with the formerly temperate climate are the only places where agriculture is still possible. ",
    ["tipping_point_5_name"] = "Warming of 3.5 °C",
    ["tipping_point_6"] = "The world has warmed by 4 degrees Celsius. Gulf Stream is irreparably disrupted. Oceans cease to mix and are losing oxygen. Marine life is nearly dead. Northern Pole is without ice much more often, even during the winter. Permafrost has completely melted, releasing giant amounts of methane. Huge deserts appear near the equator and subtropical climate areas get searingly hot and extremely damp. Massive migration towards the poles begins. Civilisation collapses, with only fraction of humanity still alive and ruled by the survival of the fittest principle.",
    ["tipping_point_6_name"] = "Warming of 4 °C",
    ["tipping_point_7"] = "The world has warmed by 5 degrees Celsius. The only habitable areas of the Earth are the Poles, the rest turned into parched deserts and extremely hot and damp regions - this means that most life, even on land, is extinct. Only a few thousand people still survive, living in tribal societies.",
    ["tipping_point_7_name"] = "Warming of 5 °C",
  },
